import './style.css'
import PremblyPass from 'prembly-pass'

const app = document.querySelector('#app')
const statusDiv = document.querySelector('#status')
const launchBtn = document.querySelector('#launch-widget')

const prembly = new PremblyPass({
  app_id: 'test_app_id',
  x_api_key: import.meta.env.VITE_PREMBLY_API_KEY,
  environment: 'test',
  sandbox_url: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref: `user_${Math.random().toString(36).substring(7)}`
});

prembly.on('success', (data) => {
  console.log('Success:', data);
  statusDiv.innerHTML = `<p style="color: green;">Verification Successful!</p><pre>${JSON.stringify(data, null, 2)}</pre>`;
});

prembly.on('error', (error) => {
  console.error('Error:', error);
  statusDiv.innerHTML = `<p style="color: red;">Verification Error: ${error.message || JSON.stringify(error)}</p>`;
});

launchBtn.addEventListener('click', () => {
  statusDiv.innerHTML = 'Launching widget...';
  prembly.launch();
});

